import org.mockito.Mockito;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithTrailingDelimiter() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        CSVFormat csvFormat = CSVFormat.newFormat(',').withQuote('\"').withDelimiter('\0').withEscape(null)
                .withHeader(null).withHeaderComments(null).withIgnoreEmptyLines(false).withIgnoreSurroundingSpaces(true)
                .withRecordSeparator("\r\n").withNullString(null).withAllowMissingColumnNames(null).withIgnoreHeaderCase(null)
                .withTrim(false).withTrailingDelimiter(false);

        // Using reflection to access the private method
        Method withTrailingDelimiterMethod = CSVFormat.class.getDeclaredMethod("withTrailingDelimiter", boolean.class);
        withTrailingDelimiterMethod.setAccessible(true);
        CSVFormat resultCsvFormat = (CSVFormat) withTrailingDelimiterMethod.invoke(csvFormat, true);

        assertTrue(resultCsvFormat.getTrailingDelimiter());
    }
}
